const STRUCTURE = [{"name": "공식요약", "count": 14, "children": [{"name": "시험직전 공식표", "count": 14}]}, {"name": "기초개념", "count": 71, "children": [{"name": "부동산학 서설", "count": 8}, {"name": "부동산의 개념과 분류", "count": 55}, {"name": "부동산의 특성", "count": 8}]}, {"name": "시장·정책·입지", "count": 392, "children": [{"name": "부동산의 수요·공급이론", "count": 156}, {"name": "부동산의 경기변동", "count": 37}, {"name": "부동산시장", "count": 35}, {"name": "입지 및 공간구조론", "count": 35}, {"name": "부동산입지선정과 입지이론", "count": 37}, {"name": "부동산정책의 의의 및 정부의 시장개입", "count": 32}, {"name": "주택정책", "count": 37}, {"name": "부동산조세정책", "count": 23}]}, {"name": "투자·금융", "count": 358, "children": [{"name": "부동산투자이론", "count": 84}, {"name": "부동산투자분석 및 기법", "count": 86}, {"name": "부동산투자분석의 기법", "count": 67}, {"name": "부동산금융", "count": 98}, {"name": "주택저당증권", "count": 23}]}, {"name": "개발·관리·마케팅", "count": 126, "children": [{"name": "부동산이용 및 개발", "count": 81}, {"name": "부동산관리", "count": 25}, {"name": "부동산마케팅", "count": 20}]}, {"name": "감정평가", "count": 156, "children": [{"name": "감정평가의 기초이론", "count": 19}, {"name": "부동산가격(가치)이론", "count": 69}, {"name": "감정평가의 방식", "count": 41}, {"name": "부동산가격공시제도", "count": 27}]}];
const LABELS = {
  must:"⭐ 반드시",
  formulaSummary:"📌 공식요약",
  formula:"🧮 공식·계산",
  study:"🃏 암기카드",
  numbers:"📅 기준·숫자",
  fill:"빈칸",
  compare:"개념비교",
  traps:"함정",
  all:"전체",
  wrong:"오답",
  fav:"별표"
};
const examDate = new Date("2026-10-31T00:00:00+09:00");
const STORAGE_PREFIX = "hakgaeron_official_v1";
let currentTab = "must";
let selectedGroup = "";
let selectedSmall = "";
let search = "";
let allData = [];
const favs = new Set(JSON.parse(localStorage.getItem(STORAGE_PREFIX+"_favs") || "[]"));
const wrongs = new Set(JSON.parse(localStorage.getItem(STORAGE_PREFIX+"_wrongs") || "[]"));
let masterCounts = JSON.parse(localStorage.getItem(STORAGE_PREFIX+"_master") || "{}");

function esc(s){return String(s??"").replace(/[&<>"']/g,m=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[m]));}
function normalize(s){return String(s??"").replace(/정답|뒷면|앞면/g,"").replace(/[①②③④⑤⑥⑦⑧⑨⑩]/g,"").replace(/[\s,./;:|()\[\]{}·㎡원]/g,"").toLowerCase();}
function candidates(item){
  const vals=[item.answer,item.allowed,item.shortAnswer,item.formulaAnswer].filter(Boolean).join(",");
  const parts=vals.split(/[\n,;/]| 또는 | 혹은 |\/|·/).map(x=>x.trim()).filter(Boolean);
  const set=new Set();
  for(const p of parts){ set.add(normalize(p)); p.split(/\s+/).forEach(t=>{ if(t) set.add(normalize(t)); }); }
  set.add(normalize(vals));
  return [...set].filter(Boolean);
}
function baseList(){
  if(currentTab==="all") return allData;
  if(currentTab==="fav") return allData.filter(x=>favs.has(x.id));
  if(currentTab==="wrong") return allData.filter(x=>wrongs.has(x.id));
  return DATASETS[currentTab] || [];
}
function match(item){
  const text=[item.largeUnit,item.largeGroup,item.smallUnit,item.category,item.type,item.title,item.question,item.answer,item.allowed,item.shortAnswer,item.formulaAnswer,item.explanation,item.memory,item.trap,item.source,...(item.tags||[])].join(" ").toLowerCase();
  if(selectedGroup && item.largeGroup!==selectedGroup) return false;
  if(selectedSmall && item.smallUnit!==selectedSmall) return false;
  if(search && !text.includes(search.toLowerCase())) return false;
  return true;
}
function setTab(tab){ currentTab=tab; render(); }
function selectUnit(group, small=""){ selectedGroup=group||""; selectedSmall=small||""; render(); }
function clearUnit(){ selectedGroup=""; selectedSmall=""; render(); }
function saveState(){
  localStorage.setItem(STORAGE_PREFIX+"_favs", JSON.stringify([...favs]));
  localStorage.setItem(STORAGE_PREFIX+"_wrongs", JSON.stringify([...wrongs]));
  localStorage.setItem(STORAGE_PREFIX+"_master", JSON.stringify(masterCounts));
}
function renderTabs(){
  const tabs=["must","formulaSummary","formula","study","numbers","fill","compare","traps","all","wrong","fav"];
  document.getElementById("tabs").innerHTML=tabs.map(t=>`<button class="${currentTab===t?'active':''}" onclick="setTab('${t}')">${LABELS[t]}</button>`).join("");
}
function masterCountForUnit(group, small=""){
  return allData.filter(x=>x.largeGroup===group && (!small || x.smallUnit===small))
    .reduce((sum,x)=>sum+((Number(masterCounts[x.id])||0)>0?1:0),0);
}
function markMastered(id){
  if((Number(masterCounts[id])||0)>0) delete masterCounts[id];
  else masterCounts[id]=1;
  saveState(); renderFolders(); renderCards();
}
function renderFolders(){
  const strip=document.getElementById("folderStrip");
  strip.innerHTML=`<button class="folder-chip ${!selectedGroup?'on':''}" onclick="clearUnit()">전체 단원</button>`+
    STRUCTURE.map(u=>`<button class="folder-chip ${selectedGroup===u.name&&!selectedSmall?'on':''}" onclick="selectUnit('${esc(u.name)}')">${esc(u.name)} · ${u.count}개 ㅡ 완전암기 ${masterCountForUnit(u.name)}/${u.count}</button>`).join("");
  const tree=document.getElementById("tree");
  tree.innerHTML=STRUCTURE.map(u=>`<div class="tree-section">
    <button class="tree-head ${selectedGroup===u.name&&!selectedSmall?'on':''}" onclick="selectUnit('${esc(u.name)}')"><span>${esc(u.name)}</span><span>${masterCountForUnit(u.name)}/${u.count}</span></button>
    <div class="tree-child">${(u.children||[]).map(c=>`<button class="${selectedSmall===c.name?'on':''}" onclick="selectUnit('${esc(u.name)}','${esc(c.name)}')">${esc(c.name)} · ${c.count}개 ㅡ 완전암기 ${masterCountForUnit(u.name,c.name)}/${c.count}</button>`).join("")}</div>
  </div>`).join("");
}
function toggleFav(id){ favs.has(id)?favs.delete(id):favs.add(id); saveState(); renderCards(); renderStats(); }
function toggleWrong(id){ wrongs.has(id)?wrongs.delete(id):wrongs.add(id); saveState(); renderCards(); renderStats(); }
function checkQuiz(id){
  const item=allData.find(x=>x.id===id); if(!item) return;
  const input=document.getElementById(`answer-${id}`);
  const result=document.getElementById(`result-${id}`);
  const user=String(input?input.value:"").trim();
  if(!user){ result.textContent="정답을 입력해."; result.className="quiz-result warn"; return; }
  const n=normalize(user);
  const ok=candidates(item).some(c=>c===n || c.includes(n) || n.includes(c));
  if(ok){ result.textContent="정답 ✅"; result.className="quiz-result correct"; }
  else{ result.textContent="오답 ❌  정답: "+(item.shortAnswer||item.answer); result.className="quiz-result wrong"; wrongs.add(id); saveState(); renderStats(); }
}
function visibleBlock(label,content,className="extra"){ if(!content) return ""; return `<div class="${className}"><strong>${label}</strong><br>${esc(content)}</div>`; }

function formulaSummaryTable(rows){
  if(!rows.length) return "";
  return `<div class="formula-table">${rows.map(item=>`
    <article class="memory-card formula-card">
      <div class="memory-top"><span class="memory-no">∑</span><div><div class="memory-title">${esc(item.title)}</div><div class="memory-meta">${esc(item.source)} · ${esc(item.level)}</div></div></div>
      <div class="memory-section"><div class="memory-label">공식/기준</div><div class="memory-content">${esc(item.formulaAnswer||item.answer)}</div></div>
      ${item.memory?`<div class="memory-section point"><div class="memory-label">판정·의미</div><div class="memory-content">${esc(item.memory)}</div></div>`:""}
      ${item.trap?`<div class="memory-section trap-card"><div class="memory-label">함정</div><div class="memory-content">${esc(item.trap)}</div></div>`:""}
    </article>`).join("")}</div>`;
}
function memoryCard(item,rowIdx,kindLabel=""){
  const done=(Number(masterCounts[item.id])||0)>0;
  return `<article class="memory-card ${done?"done":""}">
    <div class="memory-top"><span class="memory-no">${rowIdx+1}</span><div><div class="memory-title">${esc(item.title)}</div><div class="memory-meta">${esc(kindLabel||item.category||"")} · ${esc(item.level||"")}</div></div></div>
    <div class="memory-section"><div class="memory-label">공부내용</div><div class="memory-content">${esc(item.answer||item.question||"-")}</div></div>
    ${item.shortAnswer?`<div class="memory-section point"><div class="memory-label">정답</div><div class="memory-content">${esc(item.shortAnswer)}</div></div>`:""}
    ${item.memory?`<div class="memory-section point"><div class="memory-label">암기포인트</div><div class="memory-content">${esc(item.memory)}</div></div>`:""}
    ${item.trap?`<div class="memory-section trap-card"><div class="memory-label">함정</div><div class="memory-content">${esc(item.trap)}</div></div>`:""}
    <div class="memory-actions"><button class="small mastered ${done?'on':''}" onclick="markMastered('${item.id}')">${done?'↺ 까먹음 처리':'✓ 완전외움'}</button></div>
  </article>`;
}
function renderGroupedCards(rows, emptyMsg, label){
  const box=document.getElementById("cards");
  if(!rows.length){ box.innerHTML=`<div class="empty">${emptyMsg}</div>`; return; }
  if(currentTab==="formulaSummary"){ box.innerHTML=formulaSummaryTable(rows); return; }
  const groups={};
  for(const item of rows){ const key=`${item.largeGroup}|||${item.smallUnit}`; if(!groups[key])groups[key]=[]; groups[key].push(item); }
  box.innerHTML=Object.entries(groups).map(([key,items],idx)=>{
    const [group,small]=key.split("|||");
    const cards=items.map((item,rowIdx)=>memoryCard(item,rowIdx,label)).join("");
    return `<details class="memory-unit" ${idx===0?"open":""}><summary><span>${esc(group)} ㅡ ${esc(small)}</span><b>${masterCountForUnit(group,small)}/${items.length}</b></summary><div class="memory-list">${cards}</div></details>`;
  }).join("");
}
function quizCard(item){
  const done=(Number(masterCounts[item.id])||0)>0;
  return `<article class="card question-card">
    <div class="badge-row"><span class="badge unit">${esc(item.largeGroup)}</span><span class="badge unit">${esc(item.smallUnit)}</span><span class="badge type">${esc(item.category)}</span><span class="badge hot">${esc(item.level||"")}</span></div>
    <div class="title">${esc(item.title)}</div>
    <div class="question">${esc(item.question)}</div>
    <div class="quiz-box"><div class="quiz-title">직접 풀기</div><input id="answer-${item.id}" class="quiz-input" placeholder="정답 입력" onkeydown="if(event.key==='Enter') checkQuiz('${item.id}')" /><button class="quiz-check" onclick="checkQuiz('${item.id}')">채점</button><div id="result-${item.id}" class="quiz-result"></div></div>
    <details><summary>정답/해설 보기</summary><div class="answer">정답: ${esc(item.shortAnswer||item.answer)}${item.explanation?"\n\n"+esc(item.explanation):""}</div></details>
    <div class="card-actions"><button class="small mastered ${done?'on':''}" onclick="markMastered('${item.id}')">${done?'↺ 까먹음 처리':'✓ 완전외움'}</button><button class="small wrong ${wrongs.has(item.id)?'on':''}" onclick="toggleWrong('${item.id}')">✕ 오답</button><button class="small fav ${favs.has(item.id)?'on':''}" onclick="toggleFav('${item.id}')">★ 별표</button></div>
  </article>`;
}
function studyCard(item){
  const done=(Number(masterCounts[item.id])||0)>0;
  return `<article class="card">
    <div class="badge-row"><span class="badge unit">${esc(item.largeGroup)}</span><span class="badge unit">${esc(item.smallUnit)}</span><span class="badge type">${esc(item.category)}</span><span class="badge hot">${esc(item.level||"")}</span></div>
    <div class="title">${esc(item.title)}</div>
    <div class="answer visible-answer">${esc(item.answer||"")}</div>
    ${item.formulaAnswer?visibleBlock("공식/정답", item.formulaAnswer, "extra visible-note"):""}
    ${item.shortAnswer?visibleBlock("정답", item.shortAnswer, "extra visible-note"):""}
    ${item.memory?visibleBlock("암기포인트", item.memory, "extra visible-note"):""}
    ${item.trap?visibleBlock("함정", item.trap, "extra trap visible-note"):""}
    <div class="card-actions"><button class="small mastered ${done?'on':''}" onclick="markMastered('${item.id}')">${done?'↺ 까먹음 처리':'✓ 완전외움'}</button><button class="small wrong ${wrongs.has(item.id)?'on':''}" onclick="toggleWrong('${item.id}')">✕ 오답</button><button class="small fav ${favs.has(item.id)?'on':''}" onclick="toggleFav('${item.id}')">★ 별표</button></div>
  </article>`;
}
function renderCards(){
  if(["study","numbers","compare","traps","formulaSummary"].includes(currentTab)) return renderGroupedCards(baseList().filter(match),"데이터가 없습니다.",LABELS[currentTab]);
  const list=baseList().filter(match);
  const box=document.getElementById("cards");
  if(!list.length){ box.innerHTML=`<div class="empty">데이터가 없습니다. 단원 선택이나 검색어를 초기화해봐.</div>`; return; }
  if(currentTab==="fill") box.innerHTML=list.map(quizCard).join("");
  else box.innerHTML=list.map(studyCard).join("");
}
function renderStats(){
  document.getElementById("mustCount").textContent=DATASETS.must.length;
  document.getElementById("formulaCount").textContent=DATASETS.formula.length + DATASETS.formulaSummary.length;
  document.getElementById("quizCount").textContent=DATASETS.fill.length;
  document.getElementById("wrongCount").textContent=wrongs.size;
}
function renderDday(){
  const diff=Math.ceil((examDate-new Date())/(1000*60*60*24));
  document.getElementById("dday").textContent=diff>=0?`D-${diff}`:`D+${Math.abs(diff)}`;
}
function render(){ renderTabs(); renderFolders(); renderCards(); renderStats(); renderDday(); }
document.addEventListener("DOMContentLoaded",()=>{
  allData=Object.entries(DATASETS).flatMap(([k,arr])=>arr.map(x=>({...x,dataGroup:k})));
  const memo=document.getElementById("memo");
  memo.value=localStorage.getItem(STORAGE_PREFIX+"_memo")||"";
  memo.addEventListener("input",()=>localStorage.setItem(STORAGE_PREFIX+"_memo",memo.value));
  document.getElementById("searchInput").addEventListener("input",e=>{ search=e.target.value.trim(); renderCards(); });
  document.getElementById("resetBtn").addEventListener("click",()=>{ search=""; selectedGroup=""; selectedSmall=""; currentTab="must"; document.getElementById("searchInput").value=""; render(); });
  render();
});
